package com.google.gson.graph;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.InstanceCreator;
import java.lang.reflect.Type;
import java.util.Map;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GraphAdapterBuilderTest {

  private GraphAdapterBuilder graphAdapterBuilder;

  @BeforeEach
  void setUp() {
    graphAdapterBuilder = new GraphAdapterBuilder();
  }

  @Test
  void addType_withValidTypeAndInstanceCreator_shouldAddAndReturnThis() {
    Type mockType = String.class;
    @SuppressWarnings("unchecked")
    InstanceCreator<Object> mockInstanceCreator = mock(InstanceCreator.class);

    GraphAdapterBuilder returned = graphAdapterBuilder.addType(mockType, mockInstanceCreator);

    assertSame(graphAdapterBuilder, returned);

    // Use reflection to check private field instanceCreators contains the added mapping
    try {
      var field = GraphAdapterBuilder.class.getDeclaredField("instanceCreators");
      field.setAccessible(true);
      @SuppressWarnings("unchecked")
      Map<Type, InstanceCreator<?>> instanceCreators =
          (Map<Type, InstanceCreator<?>>) field.get(graphAdapterBuilder);
      assertTrue(instanceCreators.containsKey(mockType));
      assertSame(mockInstanceCreator, instanceCreators.get(mockType));
    } catch (NoSuchFieldException | IllegalAccessException e) {
      fail("Reflection failed: " + e.getMessage());
    }
  }

  @Test
  void addType_withNullType_shouldThrowNullPointerException() {
    @SuppressWarnings("unchecked")
    InstanceCreator<Object> mockInstanceCreator = mock(InstanceCreator.class);
    assertThrows(NullPointerException.class, () -> graphAdapterBuilder.addType(null, mockInstanceCreator));
  }

  @Test
  void addType_withNullInstanceCreator_shouldThrowNullPointerException() {
    Type mockType = String.class;
    assertThrows(NullPointerException.class, () -> graphAdapterBuilder.addType(mockType, null));
  }
}
